package ua.university.sms.controller;import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import ua.university.sms.model.dto.StudentDtos.*;import ua.university.sms.model.entity.StudentStatus;import ua.university.sms.service.StudentService;import java.util.*;
@RestController @RequestMapping("/api/students") public class StudentController{private final StudentService s;public StudentController(StudentService s){this.s=s;}@PostMapping public ResponseEntity<Response> create(@Valid @RequestBody Request r){return ResponseEntity.status(201).body(s.create(r));}@GetMapping("/{id}") public Response get(@PathVariable Long id){return s.get(id);}@GetMapping public List<Response> list(@RequestParam(required=false) StudentStatus status,@RequestParam(required=false) Integer year,@RequestParam(required=false) String search){return s.list(status,year,search);}@GetMapping("/unpaid") public List<Response> unpaid(){return s.unpaid();}@GetMapping("/top") public List<Response> top(@RequestParam(defaultValue="5") int limit){return s.top(limit);}@PutMapping("/{id}") public Response update(@PathVariable Long id,@Valid @RequestBody Request r){return s.update(id,r);}@DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable Long id){s.delete(id);}}
